import { useQuery, useInfiniteQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Restaurant } from "./useRestaurants";

/**
 * Ultra-lightweight query for map markers only.
 * Fetches minimal fields needed to render pins on the map.
 */
export interface LandmarkMarker {
  id: string;
  name: string;
  name_en?: string;
  name_pt?: string;
  address: string;
  lat: number;
  lng: number;
  rating?: number;
  type: string[];
  type_en?: string[];
  type_pt?: string[];
  template?: string;
}

const MARKER_FIELDS = "id,name,name_en,name_pt,address,lat,lng,rating,type,type_en,type_pt,template";

export const useLandmarkMarkers = (searchQuery?: string) => {
  return useQuery({
    queryKey: ["landmark-markers", searchQuery],
    queryFn: async () => {
      const pageSize = 1000;
      let allData: LandmarkMarker[] = [];
      let from = 0;
      let hasMore = true;

      while (hasMore) {
        let query = supabase
          .from("restaurants")
          .select(MARKER_FIELDS)
          .eq("visible", true)
          .eq("template", "landmark")
          .order("rating", { ascending: false })
          .range(from, from + pageSize - 1);

        if (searchQuery) {
          query = query.or([
            `name.ilike.%${searchQuery}%`,
            `name_en.ilike.%${searchQuery}%`,
            `name_pt.ilike.%${searchQuery}%`,
            `address.ilike.%${searchQuery}%`,
          ].join(','));
        }

        const { data, error } = await query;
        if (error) throw error;

        allData = allData.concat(data as LandmarkMarker[]);
        hasMore = (data?.length || 0) === pageSize;
        from += pageSize;
      }

      return allData;
    },
    staleTime: 1000 * 60 * 10,
    gcTime: 1000 * 60 * 20,
  });
};

/**
 * Paginated query for sidebar list items.
 * Loads landmarks in small batches as user scrolls.
 */
const SIDEBAR_PAGE_SIZE = 20;

export const useLandmarkList = (
  searchQuery?: string,
  userLocation?: { lat: number; lng: number } | null,
  radiusKm?: number | null
) => {
  return useInfiniteQuery({
    queryKey: [
      "landmark-list",
      searchQuery,
      userLocation?.lat ?? null,
      userLocation?.lng ?? null,
      radiusKm ?? null,
    ],
    queryFn: async ({ pageParam = 0 }) => {
      const { data, error } = await supabase.rpc("get_restaurants_paginated", {
        p_offset: pageParam,
        p_limit: SIDEBAR_PAGE_SIZE,
        p_search: searchQuery || null,
        p_country: null,
        p_city: null,
        p_district: null,
        p_template: "landmark",
        p_verified: null,
        p_type_filter: null,
        p_activity_id: null,
        p_user_lat: userLocation?.lat ?? null,
        p_user_lng: userLocation?.lng ?? null,
        p_radius_km: radiusKm ?? null,
        p_sort_by_distance: Boolean(userLocation),
        p_michelin_star: null,
      });

      if (error) throw error;

      const result = data as {
        data?: (Restaurant & { distance_km?: number | null })[];
        total?: number;
      };

      const items = (result?.data || []).map((restaurant) => ({
        ...restaurant,
        distance: restaurant.distance_km ?? undefined,
      })) as Restaurant[];

      const total = result?.total ?? 0;
      const nextOffset = total > 0
        ? (pageParam + SIDEBAR_PAGE_SIZE < total ? pageParam + SIDEBAR_PAGE_SIZE : undefined)
        : ((items.length || 0) === SIDEBAR_PAGE_SIZE ? pageParam + SIDEBAR_PAGE_SIZE : undefined);

      return {
        items,
        nextOffset,
      };
    },
    initialPageParam: 0,
    getNextPageParam: (lastPage) => lastPage.nextOffset,
    staleTime: 1000 * 60 * 10,
    gcTime: 1000 * 60 * 20,
  });
};
